mapper.select:
/* selectTransportList */ select concat(OS.COMPKEY, OS.POSTDAT, OS.SAATC06) as ROWKEY , OS.COMPKEY , MW.WHNAMLC , IFNULL(OS.TOWARKY, ' ') as TOWARKY , Fn_com_todate(OS.POSTDAT) as POSTDAT , OS.SAATC06 , MP.PTNAMLC , OS.CUSTKEY , MD.DENAMLC , OS.DESTKEY , OS.DOCCATE , MO.OCOCTNM , OS.DOCTYPE , MO.COOTYNM , OS.TRNSTAT as OSTRNST , (select MC.COMCDTX from V_MCODEM MC where MC.COMPKEY = OS.COMPKEY AND MC.COMCDKY = 'TRNSTAT' AND MC.COMCDVL = OS.TRNSTAT ) AS TRNSTAT , (select MC.COMCDTX from V_MCODEM MC where MC.COMPKEY = OS.COMPKEY AND MC.COMCDKY = 'OUBSTAT' AND MC.COMCDVL = OS.OUBSTAT ) AS OUBSTAT , min(OS.SAATC07) as SAATC07 , min(OS.SAATC08) as SAATC08 , min(OS.SAATC10) as SAATC10MIN , max(OS.SAATC10) as SAATC10MAX , TH.VHPLNKY , sum(OS.RGITQTY) as RGITQTY , TH.VEHICKY , min(OS.SAATC01) as SAATC01 , min(OS.SAATC03) as SAATC03 , min(OS.SAATC05) as SAATC05 , min(OS.SAATC02) as SAATC02 , min(OS.SAATC04) as SAATC04 , min(OS.SAATC06) as SAATC06 , min(OS.SAATC09) as SAATC09 , (select T.VHCSNAM from TVHCMA T WHERE T.COMPKEY =TH.COMPKEY AND T.VEHICKY = TH.VEHICKY ) as VHCSNAM , MAX(IF(NULLIF(OS.CREDATE,''), DATE_FORMAT(OS.CREDATE, '%Y-%m-%d'), ' ')) as CREDATE , MAX((CASE WHEN CHAR_LENGTH(OS.CRETIME) = 6 THEN CONCAT(SUBSTRING(OS.CRETIME, 1, 2), ':', SUBSTRING(OS.CRETIME, 3, 2), ':', SUBSTRING(OS.CRETIME, 5, 2)) ELSE '00:00:00' END )) as CRETIME , MAX((SELECT USERNAM from V_SUSRMA WHERE COMPKEY = OS.COMPKEY AND USERACT = OS.CREUSER)) as CREUSER , MAX(IF(NULLIF(OS.LMODATE,''), DATE_FORMAT(OS.LMODATE, '%Y-%m-%d'), ' ')) as LMODATE , MAX((CASE WHEN CHAR_LENGTH(OS.LMOTIME) = 6 THEN CONCAT(SUBSTRING(OS.LMOTIME, 1, 2), ':', SUBSTRING(OS.LMOTIME, 3, 2), ':', SUBSTRING(OS.LMOTIME, 5, 2)) ELSE '00:00:00' END )) as LMOTIME , MAX((SELECT USERNAM from V_SUSRMA WHERE COMPKEY = OS.COMPKEY AND USERACT = OS.LMOUSER)) as LMOUSER FROM OCOSAL OS FORCE INDEX(IX_OCOSAL04) left join TPLNIT TI on OS.COMPKEY = TI.COMPKEY and OS.COOUTKY = TI.COOUTKY and OS.COOUTIT = TI.COOUTIT left join TPLNHD TH on TI.COMPKEY = TH.COMPKEY and TI.VHPLNKY = TH.VHPLNKY inner join MWARMA MW on MW.COMPKEY = OS.COMPKEY and MW.WAREKEY = OS.TOWARKY inner join MPTNMA MP on MP.COMPKEY = OS.COMPKEY and MP.PTNRKEY = OS.CUSTKEY inner join MDESMA MD on MD.COMPKEY = OS.COMPKEY and MD.PTNRKEY = OS.CUSTKEY and MD.DESTKEY = OS.DESTKEY inner join MORDMA MO on MO.COMPKEY = OS.COMPKEY and MO.WAREKEY = OS.TOWARKY and MO.COOTYPE = OS.DOCTYPE and MO.COOCATE = OS.DOCCATE left outer join OCATMA OC on OC.COMPKEY = OS.COMPKEY and OC.WAREKEY = OS.TOWARKY and OC.DOCCATE = '200' and OC.DOCTYPE = '213' and OC.SCATECD = OS.SAATC07 where OS.COMPKEY = #{userData.compkey} and OS.SALSTAT != 'CANCEL' and OS.DOCTYPE IN ('210', '211', '212', '213', '229', '230', '240', '290')
and OS.TOWARKY = #{towarky}
and replace(OS.DESTKEY, ' ', '') like concat('%', #{destkey}, '%')
and replace(OS.DOCTYPE, ' ', '') like concat('%', #{doctype}, '%')
and replace(upper(OC.MCATENM), ' ', '') like concat('%', upper(#{saatc08}), '%')
and OS.SAATC10 like concat('%', #{saatc10}, '%')
and replace(OS.SAATC06, ' ', '') like concat('%', upper(#{saatc06}), '%')
and OS.POSTDAT >= #{postdatFrom}
and OS.POSTDAT <= #{postdatTo}
and OS.POSTDAT between #{postdatFrom} and #{postdatTo}
and OS.SALSTAT = #{salstat}
and OS.OUBSTAT = #{oubstat}
and OS.TRNSTAT IN
#{trnstat}
and OS.TRNSTAT = #{trnstat}
group by OS.COMPKEY, OS.TOWARKY, OS.POSTDAT , OS.SAATC06 , OS.CUSTKEY, OS.DESTKEY , OS.TRNSTAT, TH.VHPLNKY, TH.VEHICKY , OS.DOCCATE, OS.DOCTYPE order by OS.POSTDAT, OS.DOCTYPE, min(OS.SAATC10), max(OS.SAATC10), OS.SAATC06, OS.CUSTKEY, OS.TOWARKY, OS.DESTKEY

/* selectTmaOcosal */ select OS.COMPKEY , Fn_com_todate(OS.POSTDAT) as POSTDAT , Fn_com_todate(OS.SALDATE) as SALDATE , Fn_com_totime(OS.SALTIME) as SALTIME , OS.VENDKEY , OS.TOWARKY , OS.CUSTKEY , OS.SALMEMO , OS.SALRQDT , OS.SALRQTM , OS.DESTKEY , OS.OWNERKY , MS.SKUMKEY , MS.SKUDESC , concat('[', MS.SKUMKEY, ']', MS.SKUDESC) as OCOSKUM , MS.SKUSKEY , OS.SOITQTY , OS.SHCFQTY , OS.DIFFQTY , OS.SUOMKEY , OS.DCTCTYP , OS.RSNCODE , OS.RSNDESC , OS.ORDGR01 , OS.ORDGR02 , OS.ORDGR03 , OS.SAATN01 , OS.SAATN02 , OS.SAATN03 , OS.SAATN04 , OS.SAATN05 , OS.SAATC01 , OS.SAATC02 , OS.SAATC03 , OS.SAATC04 , OS.SAATC05 , OS.SAATC06 , OS.SAATC07 , OS.SAATC08 , OS.SAATC09 , OS.SAATC10 , OS.SAATC11 , OS.SAATC12 , OS.SAATC13 , OS.CLOSLYN , OS.CLODATE , OS.CLOTIME , OS.CLOUSER , OS.BTHDCKY , OS.BTHDCIT , Fn_com_todate(OS.CREDATE) as CREDATE , Fn_com_totime(OS.CRETIME) as CRETIME , fn_sy_usernam(OS.COMPKEY, OS.CREUSER) as CREUSER , Fn_com_todate(OS.LMODATE) as LMODATE , Fn_com_totime(OS.LMOTIME) as LMOTIME , OS.LMOUSER , OS.INDIBZL , OS.INDIARC , OS.UPDTCHK , OS.COOUTKY , OS.COOUTIT , OS.DOCCATE , OS.DOCTYPE , OS.RGITQTY , MP.PTNAMLC , MD.DENAMLC , MW.OWNAMLC , MO.OCOCTNM , MO.COOTYNM , OS.TRNSTAT , OS.SALSTAT , OS.OUBSTAT , OS.INBSTAT from OCOSAL OS inner join MPTNMA MP on MP.COMPKEY = OS.COMPKEY and MP.PTNRKEY = OS.CUSTKEY inner join MDESMA MD on MD.COMPKEY = OS.COMPKEY and MD.PTNRKEY = OS.CUSTKEY and MD.DESTKEY = OS.DESTKEY inner join MORDMA MO on MO.COMPKEY = OS.COMPKEY and MO.WAREKEY = OS.TOWARKY and MO.COOTYPE = OS.DOCTYPE and MO.COOCATE = OS.DOCCATE inner join MOWRMA MW on MW.COMPKEY = OS.COMPKEY and MW.OWNERKY = OS.OWNERKY inner join MSKUWC MS on MS.COMPKEY = OS.COMPKEY and MS.WAREKEY = OS.TOWARKY and MS.OWNERKY = OS.OWNERKY and MS.SKUMKEY = OS.SKUMKEY where OS.COMPKEY = #{userData.compkey} and OS.SALSTAT != 'CANCEL' and OS.DOCCATE = #{doccate} and OS.DOCTYPE = #{doctype}
and OS.SAATC06 = #{saatc06}
and OS.SAATC06 is NULL
and OS.DESTKEY = #{destkey}
and OS.DESTKEY is NULL
and OS.POSTDAT = #{postdat}
and OS.POSTDAT is NULL
and OS.TRNSTAT = #{trnstat}
order by OS.COOUTKY, OS.COOUTIT

select count(*)
from TPLNIT
where COMPKEY = #{userData.compkey}
and VHPLNKY = #{vhplnky}

