	PLNSTAT, PBILPAY, CREDATE, CRETIME,
	CREUSER, LMODATE, LMOTIME, LMOUSER, UPDTCHK,
	STPITDT, STPITTM

		, PBILLYN


		, EMERSCD


		, EMERDNM


		, TRAREKY


		, SHTRTKY

)
values
(
	#{userData.compkey}, #{vhplnky}, #{warekey}, #{vehicky}, #{doccate},
	#{doctype}, #{postdat}, date_format(NOW(),'%Y%m%d'), date_format(NOW(),'%H%i%s'), ifnull(#{trnmemo}, ''),
	#{plnstat}, #{pbilpay}, date_format(NOW(),'%Y%m%d'), date_format(NOW(),'%H%i%s'),
	#{userData.useract}, date_format(NOW(),'%Y%m%d'), date_format(NOW(),'%H%i%s'), #{userData.useract}, #{updtchk},
	ifnull(#{stpitdt}, ''), ifnull(#{stpittm}, '')

		, #{pbillyn}


		, #{emerscd}


		, #{emerdnm}


		, #{trareky}


		, #{shtrtky}

)

/* insertTmaCommonTplnitItem */ insert into TPLNIT( COMPKEY, VHPLNKY, VHPLNIT, WAREKEY, CUSTKEY, DESTKEY, OWNERKY, SKUMKEY, SKUDESC, SKUSKEY, SOITQTY, TRITQTY, SUOMKEY, SAATN01, SAATN02, SAATN03, SAATN04, SAATN05, SAATC01, SAATC02, SAATC03, SAATC04, SAATC05, SAATC06, SAATC07, SAATC08, SAATC09, SAATC10, COOUTKY, COOUTIT, CREDATE, CRETIME, CREUSER, LMODATE, LMOTIME, LMOUSER, UPDTCHK
, TRUNTYP
, TRUNPID
, RETODYN
) values ( #{userData.compkey}, #{vhplnky}, FN_TM_VHPLNIT(#{userData.compkey}, #{vhplnky}), #{towarky}, #{custkey}, #{destkey}, #{ownerky}, #{skumkey}, #{skudesc}, ifnull(#{skuskey}, ''), #{soitqty}, #{soitqty}, #{suomkey}, ifnull(#{saatn01}, ''), ifnull(#{saatn02}, ''), ifnull(#{saatn03}, ''), ifnull(#{saatn04}, ''), ifnull(#{saatn05}, ''), ifnull(#{saatc01}, ''), ifnull(#{saatc02}, ''), ifnull(#{saatc03}, ''), ifnull(#{saatc04}, ''), ifnull(#{saatc05}, ''), ifnull(#{saatc06}, ''), ifnull(#{saatc07}, ''), ifnull(#{saatc08}, ''), ifnull(#{saatc09}, ''), ifnull(#{saatc10}, ''), #{cooutky}, #{cooutit}, date_format(NOW(),'%Y%m%d'), date_format(NOW(),'%H%i%s'), #{userData.useract}, date_format(NOW(),'%Y%m%d'), date_format(NOW(),'%H%i%s'), #{userData.useract}, #{updtchk}
, #{truntyp}
, #{trunpid}
, #{retodyn}
)

