update TPLNIT
   set SAATC01 = #{saatc01}
     , SAATC02 = #{saatc02}
     , SAATC03 = #{saatc03}
     , SAATC04 = #{saatc04}
     , SAATC05 = #{saatc05}
     , SAATC06 = #{saatc06}
     , SAATC07 = #{saatc07}
     , SAATC09 = #{saatc09}
     , SAATC10 = #{saatc10}
     , LMODATE = date_format(NOW(), '%Y%m%d')
     , LMOTIME = date_format(NOW(), '%H%i%s')
     , LMOUSER = #{userData.useract}
 where COMPKEY = #{userData.compkey}
