select VHPLNKY
	 , VHPLNIT
	 , UPDTCHK
  from TPLNIT
 where COMPKEY = #{userData.compkey}
   and COOUTKY = #{cooutky}
   and COOUTIT = #{cooutit}

/* selectTma04ShuttleList */ select concat(TD.COMPKEY, TD.WAREKEY, TD.SHTRTKY) as ROWKEY , TD.SHTRTNM , TD.SHTMEMO , TV.VHCSNAM , TH.SHTVCAP , TD.SHTRTKY , MD.DOCCTNM , MD.DOCTYNM , MD.DOCCATE , MD.DOCTYPE , TH.VEHICKY , TD.WAREKEY , TH.SRVEHOD from TSHRHD TD inner join ( select COMPKEY, WAREKEY, SHTRTKY, VEHICKY, SHTVCAP, SRVEHOD from TSHRVH where COMPKEY = #{userData.compkey} ) TH on TH.COMPKEY = TD.COMPKEY and TH.WAREKEY = TD.WAREKEY and TH.SHTRTKY = TD.SHTRTKY inner join TVHCMA TV on TV.COMPKEY = TD.COMPKEY and TV.WAREKEY = TD.WAREKEY and TV.VEHICKY = TH.VEHICKY inner join ( select count(TT.DESTKEY) as SHTRTKY_COUNT, TT.SHTRTKY from TSHRIT TT inner join ( select count(shtrpty) as SHTRPTY_COUNT, SHTRTKY, WAREKEY, COMPKEY from TSHRIT where SHTRPTY = 'ARRIVAL' group by SHTRTKY )SUBT on TT.COMPKEY = SUBT.COMPKEY and TT.WAREKEY = SUBT.WAREKEY and TT.SHTRTKY = SUBT.SHTRTKY where TT.DESTKEY in
#{destkey}
and SUBT.SHTRPTY_COUNT = #{dtcount} group by TT.SHTRTKY ) SUBT on TD.SHTRTKY = SUBT.SHTRTKY inner join ( select DOCCTNM, DOCTYNM, COMPKEY, WAREKEY, DOCCATE, DOCTYPE from MDOCMA where COMPKEY = #{userData.compkey} ) MD on MD.COMPKEY = TD.COMPKEY and MD.WAREKEY = TD.WAREKEY and MD.DOCTYPE = '820' where TD.COMPKEY = #{userData.compkey} and TD.TSUSEYN = 'Y' and SUBT.SHTRTKY_COUNT = #{dtcount} and TD.WAREKEY = #{warekey}
and TD.SHTGRNM like concat('%', #{shtgrnm}, '%')
order by TD.SHTRTKY, TH.SRVEHOD

/* selectTma06PlanList */ select concat(TP.COMPKEY, TP.VHPLNKY) as ROWKEY , TP.VHPLNKY , TV.VHCSNAM , MD.DENAMLC , TI.DESTKEY , MAX(TI.REPITTM) as REPITTM , TI.SHTRPTY , ( select MC.COMCDTX from V_MCODEM MC where MC.COMPKEY = TP.COMPKEY AND MC.COMCDKY = 'PLNSTAT' and MC.COMCDVL = TP.PLNSTAT ) as PLNSTAT , min(TI.SAATC10) from TPLNHD TP inner join TPLNIT TI ON TI.COMPKEY = TP.COMPKEY AND TI.VHPLNKY = TP.VHPLNKY inner join TVHCMA TV ON TV.COMPKEY = TP.COMPKEY AND TV.WAREKEY = TP.WAREKEY AND TV.VEHICKY = TP.VEHICKY inner join MDESMA MD on MD.COMPKEY = TI.COMPKEY and MD.PTNRKEY = TI.CUSTKEY and MD.DESTKEY = TI.DESTKEY where TP.COMPKEY = #{userData.compkey} and TP.POSTDAT in
#{postdat}
and TP.WAREKEY in
#{warekey}
and TP.PLNSTAT IN
#{plnstat}
and TI.DESTKEY in
#{destkey}
and TP.DOCTYPE not in ('830') group by TP.COMPKEY, TP.VHPLNKY, TV.VHCSNAM, MD.DENAMLC , TI.DESTKEY, TI.SHTRPTY order by TP.VHPLNKY DESC

/* selectTma06CarList */ select concat(TV.COMPKEY, TV.WAREKEY, TV.VEHICKY) as ROWKEY , TV.VHCSNAM , TV.VEHGRNM , TV.VEHCSNM , TV.VEHTPYN , TV.VHCMEMO , MD.DOCCTNM , MD.DOCTYNM , MD.DOCCATE , MD.DOCTYPE , TV.WAREKEY , TV.VEHICKY , TV.OWNERNM from TVHCMA TV inner join ( select DOCCTNM, DOCTYNM, COMPKEY, WAREKEY, DOCCATE, DOCTYPE from MDOCMA where COMPKEY = #{userData.compkey} ) MD on MD.COMPKEY = TV.COMPKEY and MD.WAREKEY = TV.WAREKEY and MD.DOCTYPE = '870' where TV.COMPKEY = #{userData.compkey} and TV.VHUSEYN = 'Y' and TV.VHRCSTS = '00' and TV.WAREKEY in
#{warekey}
order by VHCSNAM, OWNERNM

